import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import axios from '../../api/axiosInstance';
import { useAppUI } from '../../contexts/AppUIContext';
import { useNotifications } from '../../contexts/NotificationContext';
import { normalizeNotificationTarget } from '../../utils/notificationRoutes';

const DAY_CODE_MAP = ['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT'];
const ATTENDANCE_DELAY_MS = 15 * 60 * 1000;
const PRE_START_ALERT_MS = 10 * 60 * 1000;

const buildDateTime = (date, timeString = '00:00:00') => {
  const [hours = 0, minutes = 0, seconds = 0] = timeString.split(':').map(Number);
  const value = new Date(date);
  value.setHours(hours, minutes, seconds || 0, 0);
  return value;
};

const isScheduledForToday = (batch, today) => {
  if (batch.batch_type === 'ONE_TIME' && batch.exact_date) {
    return batch.exact_date === today.toISOString().split('T')[0];
  }
  return batch.schedule_day === DAY_CODE_MAP[today.getDay()];
};

const formatRelativeDuration = (milliseconds) => {
  if (milliseconds <= 0) {
    return 'now';
  }

  const totalMinutes = Math.ceil(milliseconds / 60000);
  if (totalMinutes < 60) {
    return `${totalMinutes} minute${totalMinutes === 1 ? '' : 's'}`;
  }

  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  if (minutes === 0) {
    return `${hours} hour${hours === 1 ? '' : 's'}`;
  }

  return `${hours} hour${hours === 1 ? '' : 's'} ${minutes} minute${minutes === 1 ? '' : 's'}`;
};

const formatCountdown = (milliseconds) => {
  const safeValue = Math.max(0, milliseconds);
  const totalSeconds = Math.ceil(safeValue / 1000);
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  return `${minutes}:${seconds.toString().padStart(2, '0')}`;
};

const Dashboard = () => {
  const { notifySuccess, notifyError, notifyInfo } = useAppUI();
  const { user } = useAuth();
  const { markRead } = useNotifications();
  const navigate = useNavigate();
  const [statsData, setStatsData] = useState(null);
  const [batches, setBatches] = useState([]);
  const [availableBatches, setAvailableBatches] = useState([]);
  const [todayAttendanceRecords, setTodayAttendanceRecords] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentTime, setCurrentTime] = useState(() => new Date());
  const preStartAlerts = useRef(new Set());

  useEffect(() => {
    fetchDashboardData();
    fetchBatches();
    fetchAvailableBatches();
    fetchTodayAttendance();
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await axios.get('/analytics/reports/dashboard_stats/');
      setStatsData(response.data);
    } catch (err) {
      console.error('Error fetching dashboard stats:', err);
    }
  };

  const fetchBatches = async () => {
    try {
      const response = await axios.get('/batches/');
      setBatches(response.data);
    } catch (error) {
      console.error('Error fetching batches:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchAvailableBatches = async () => {
    try {
      const response = await axios.get('/batches/unassigned/');
      setAvailableBatches(response.data);
    } catch (error) {
      console.error('Error fetching available batches:', error);
    }
  };

  const fetchTodayAttendance = async () => {
    try {
      const response = await axios.get('/coaches/');
      const today = new Date().toISOString().split('T')[0];
      const records = response.data.filter(r => r.date === today);
      setTodayAttendanceRecords(records);
    } catch (error) {
      console.error('Error fetching today attendance:', error);
    }
  };

  const handleClockIn = async (batchId) => {
    try {
      await axios.post('/coaches/clock_in/', { batch_id: batchId });
      notifySuccess('Clocked in successfully.');
      fetchTodayAttendance();
    } catch (error) {
      notifyError('Failed to clock in.');
    }
  };

  const handleClockOut = async (batchId) => {
    try {
      await axios.post('/coaches/clock_out/', { batch_id: batchId });
      notifySuccess('Clocked out successfully.');
      fetchTodayAttendance();
    } catch (error) {
      notifyError('Failed to clock out.');
    }
  };

  const handleNotificationClick = async (notif) => {
    try {
      if (!notif.is_read) {
        await markRead(notif.id);
      }
      const targetUrl = normalizeNotificationTarget(notif.target_url);
      if (targetUrl) navigate(targetUrl);
    } catch (err) {
      console.error('Error marking notification as read:', err);
      const targetUrl = normalizeNotificationTarget(notif.target_url);
      if (targetUrl) navigate(targetUrl);
    }
  };

  const todaysBatches = useMemo(() => {
    return batches
      .filter((batch) => isScheduledForToday(batch, currentTime))
      .map((batch) => {
        const startAt = buildDateTime(currentTime, batch.start_time);
        const endAt = buildDateTime(currentTime, batch.end_time);
        return {
          ...batch,
          startAt,
          endAt,
          attendanceOpensAt: new Date(startAt.getTime() + ATTENDANCE_DELAY_MS),
        };
      })
      .sort((left, right) => left.startAt - right.startAt);
  }, [batches, currentTime]);

  const nextUpcomingBatch = useMemo(
    () => todaysBatches.find((batch) => batch.startAt > currentTime) || null,
    [todaysBatches, currentTime],
  );

  const currentBatch = useMemo(
    () => todaysBatches.find((batch) => currentTime >= batch.startAt && currentTime <= batch.endAt) || null,
    [todaysBatches, currentTime],
  );

  const currentBatchAttendance = useMemo(() => {
    if (!currentBatch) {
      return null;
    }
    return todayAttendanceRecords.find((record) => record.batch === currentBatch.id) || null;
  }, [currentBatch, todayAttendanceRecords]);

  const nextClassMessage = useMemo(() => {
    if (currentBatch) {
      return `"${currentBatch.batch_name}" is in progress right now.`;
    }
    if (nextUpcomingBatch) {
      return `Next class starts in ${formatRelativeDuration(nextUpcomingBatch.startAt - currentTime)}.`;
    }
    return 'No more classes are scheduled for today.';
  }, [currentBatch, nextUpcomingBatch, currentTime]);

  const attendanceCountdown = currentBatch
    ? Math.max(0, currentBatch.attendanceOpensAt - currentTime)
    : 0;
  const attendanceReady = currentBatch && currentTime >= currentBatch.attendanceOpensAt;
  const attendanceAlreadyStarted = !!currentBatchAttendance?.clock_in_time;

  useEffect(() => {
    if (!nextUpcomingBatch) {
      return;
    }

    const millisecondsUntilStart = nextUpcomingBatch.startAt - currentTime;
    const alertKey = `${nextUpcomingBatch.id}-${nextUpcomingBatch.startAt.toISOString()}`;

    if (
      millisecondsUntilStart > 0 &&
      millisecondsUntilStart <= PRE_START_ALERT_MS &&
      !preStartAlerts.current.has(alertKey)
    ) {
      preStartAlerts.current.add(alertKey);
      notifyInfo(`${nextUpcomingBatch.batch_name} is going to start in ${formatRelativeDuration(millisecondsUntilStart)}.`);
    }
  }, [nextUpcomingBatch, currentTime, notifyInfo]);

  return (
    <div className="container-fluid p-0">
      <h3 className="fw-bold mb-4">Welcome, {user?.username || 'Coach'}</h3>

      <div className="row g-4 mb-5">
        <div className="col-md-4">
          <div className="card border-0 shadow-sm p-4 bg-success-subtle rounded-4">
            <small className="text-secondary fw-bold d-block mb-1">Your Batches</small>
            <h3 className="fw-bold m-0 text-success">{batches.length}</h3>
          </div>
        </div>

        {/* New Widget for Batch Opportunities */}
        <div className="col-md-4">
          <div className="card border-0 shadow-sm p-4 bg-primary-subtle rounded-4 h-100" style={{ cursor: 'pointer' }} onClick={() => navigate('/coach/batch-applications')}>
            <div className="d-flex justify-content-between align-items-center">
              <div>
                <small className="text-primary fw-bold d-block mb-1">Open Opportunities</small>
                <h3 className="fw-bold m-0 text-primary">{availableBatches.length}</h3>
              </div>
              <i className="bi bi-briefcase fs-1 text-primary opacity-25"></i>
            </div>
            <small className="text-primary mt-2 d-block">Click to view & apply</small>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card border-0 shadow-sm p-4 bg-light rounded-4 h-100">
            <div className="d-flex justify-content-between align-items-center">
              <div>
                <small className="text-secondary fw-bold d-block mb-1">Total Hours</small>
                <h3 className="fw-bold m-0 text-secondary">--</h3>
              </div>
              <i className="bi bi-clock-history fs-1 text-secondary opacity-25"></i>
            </div>
            <small className="text-secondary mt-2 d-block">View History</small>
          </div>
        </div>

      </div>

      <div className="card border-0 shadow-sm rounded-4 mb-4 overflow-hidden">
        <div className="p-3 text-white" style={{ backgroundColor: '#6c9343' }}>
          <h5 className="fw-bold m-0">Today&apos;s Class Tracker</h5>
        </div>
        <div className="p-4">
          <div className="row g-4 align-items-stretch">
            <div className="col-lg-7">
              <div className="h-100 rounded-4 p-4" style={{ background: 'linear-gradient(135deg, #f5faef 0%, #eef6e2 100%)' }}>
                <small className="text-uppercase fw-bold text-success d-block mb-2">Next Session</small>
                <h4 className="fw-bold mb-2">
                  {currentBatch?.batch_name || nextUpcomingBatch?.batch_name || 'No upcoming class'}
                </h4>
                <p className="text-secondary mb-3">{nextClassMessage}</p>
                {(currentBatch || nextUpcomingBatch) && (
                  <div className="d-flex flex-wrap gap-3 text-secondary small">
                    <span>
                      <i className="bi bi-calendar-event me-2 text-success"></i>
                      {currentBatch?.schedule_day || nextUpcomingBatch?.schedule_day}
                    </span>
                    <span>
                      <i className="bi bi-clock me-2 text-success"></i>
                      {currentBatch?.start_time || nextUpcomingBatch?.start_time} - {currentBatch?.end_time || nextUpcomingBatch?.end_time}
                    </span>
                  </div>
                )}
              </div>
            </div>

            <div className="col-lg-5">
              <div className="h-100 rounded-4 border p-4 bg-white">
                {!currentBatch ? (
                  <>
                    <small className="text-uppercase fw-bold text-primary d-block mb-2">Attendance Window</small>
                    <h6 className="fw-bold mb-2">Waiting for class to begin</h6>
                    <p className="text-muted mb-0">
                      {nextUpcomingBatch
                        ? `Attendance access will unlock 15 minutes after ${nextUpcomingBatch.batch_name} starts.`
                        : 'A countdown and attendance shortcut will appear here when a class is due today.'}
                    </p>
                  </>
                ) : attendanceAlreadyStarted ? (
                  <>
                    <small className="text-uppercase fw-bold text-success d-block mb-2">Attendance Status</small>
                    <h6 className="fw-bold mb-2">Attendance already opened for this class</h6>
                    <p className="text-muted mb-3">
                      {currentBatchAttendance?.clock_out_time
                        ? 'This session has already been recorded.'
                        : 'You have already started attendance for the active class.'}
                    </p>
                    <button
                      className="btn btn-success fw-bold px-4"
                      onClick={() => navigate('/coach/mark-attendance', {
                        state: {
                          batchId: currentBatch.id,
                          batchName: currentBatch.batch_name,
                        },
                      })}
                    >
                      Continue Attendance
                    </button>
                  </>
                ) : attendanceReady ? (
                  <>
                    <small className="text-uppercase fw-bold text-success d-block mb-2">Attendance Window</small>
                    <h6 className="fw-bold mb-2">Attendance is now available</h6>
                    <p className="text-muted mb-3">
                      {currentBatch.batch_name} started more than 15 minutes ago. You can open the attendance page now.
                    </p>
                    <button
                      className="btn btn-success fw-bold px-4"
                      onClick={() => navigate('/coach/mark-attendance', {
                        state: {
                          batchId: currentBatch.id,
                          batchName: currentBatch.batch_name,
                        },
                      })}
                    >
                      Mark Attendance for {currentBatch.batch_name}
                    </button>
                  </>
                ) : (
                  <>
                    <small className="text-uppercase fw-bold text-warning d-block mb-2">Attendance Window</small>
                    <h6 className="fw-bold mb-2">Attendance taking starts in 15 minutes</h6>
                    <div className="display-6 fw-bold text-warning mb-2">{formatCountdown(attendanceCountdown)}</div>
                    <p className="text-muted mb-0">
                      The attendance button will appear here after the first 15 minutes of the live class.
                    </p>
                  </>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="row g-4">
        <div className="col-md-8">
          <h5 className="fw-bold mb-3">Your Batch Sessions</h5>
          {batches.map(batch => (
            <div key={batch.id} className="card border-0 shadow-sm p-3 mb-3">
              <div className="d-flex justify-content-between align-items-center">
                <div>
                  <h6 className="fw-bold m-0">{batch.batch_name}</h6>
                  <small className="text-muted">{batch.schedule_day}s, {batch.start_time} - {batch.end_time}</small>
                </div>
                <div className="d-flex gap-2">
                  {currentBatch?.id === batch.id ? (
                    attendanceAlreadyStarted || attendanceReady ? (
                      <button
                        className="btn btn-success"
                        onClick={() => navigate('/coach/mark-attendance', {
                          state: {
                            batchId: batch.id,
                            batchName: batch.batch_name
                          }
                        })}
                      >
                        {attendanceAlreadyStarted ? 'Continue Attendance' : 'Mark My Attendance'}
                      </button>
                    ) : (
                      <span className="badge bg-warning-subtle text-warning-emphasis px-3 py-2">
                        Opens in {formatCountdown(attendanceCountdown)}
                      </span>
                    )
                  ) : nextUpcomingBatch?.id === batch.id ? (
                    <span className="badge bg-info-subtle text-info-emphasis px-3 py-2">
                      Starts in {formatRelativeDuration(nextUpcomingBatch.startAt - currentTime)}
                    </span>
                  ) : (
                    <button
                      className="btn btn-outline-success"
                      onClick={() => navigate('/coach/mark-attendance', {
                        state: {
                          batchId: batch.id,
                          batchName: batch.batch_name
                        }
                      })}
                    >
                      View Attendance Page
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
          {batches.length === 0 && <p className="text-muted">No active batches.</p>}
        </div>

        <div className="col-md-4">
          <h5 className="fw-bold mb-3">Quick Actions</h5>
          <div className="d-grid gap-3">
            <div className="p-3 bg-white rounded-3 shadow-sm border" style={{ cursor: 'pointer' }} onClick={() => navigate('/coach/batch-applications')}>
              <div className="d-flex align-items-center gap-3">
                <i className="bi bi-briefcase text-success fs-5"></i>
                <div>
                  <h6 className="m-0 fw-bold">Apply for Batches</h6>
                  <small className="text-muted">View available slots</small>
                </div>
              </div>
            </div>
            <div className="p-3 bg-white rounded-3 shadow-sm border" style={{ cursor: 'pointer' }} onClick={() => navigate('/coach/attendance')}>
              <div className="d-flex align-items-center gap-3">
                <i className="bi bi-clock-history text-success fs-5"></i>
                <div>
                  <h6 className="m-0 fw-bold">View Attendance</h6>
                  <small className="text-muted">Check your history</small>
                </div>
              </div>
            </div>
            <div className="p-3 bg-white rounded-3 shadow-sm border" style={{ cursor: 'pointer' }} onClick={() => navigate('/coach/salary')}>
              <div className="d-flex align-items-center gap-3">
                <i className="bi bi-cash-coin text-warning fs-5"></i>
                <div>
                  <h6 className="m-0 fw-bold">Salary History</h6>
                  <small className="text-muted">View payments</small>
                </div>
              </div>
            </div>
          </div>

          {/* Recent Notifications Card */}
          <div className="card border-0 shadow-sm rounded-4 mt-4 overflow-hidden">
            <div className="p-3 bg-light border-bottom d-flex justify-content-between align-items-center">
              <h6 className="fw-bold m-0" style={{ color: '#6c9343' }}>Recent Notifications</h6>
              <span className="badge rounded-pill bg-success" style={{ backgroundColor: '#6c9343' }}>{statsData?.notifications || 0} New</span>
            </div>
            <div className="list-group list-group-flush">
              {!statsData?.recent_notifications || statsData.recent_notifications.length === 0 ? (
                <div className="p-4 text-center text-muted">No notifications yet.</div>
              ) : (
                statsData.recent_notifications.map((notif) => (
                  <div
                    key={notif.id}
                    className={`list-group-item list-group-item-action p-3 border-start border-4 ${!notif.is_read ? 'border-success bg-light' : 'border-transparent'}`}
                    onClick={() => handleNotificationClick(notif)}
                    style={{ cursor: 'pointer' }}
                  >
                    <div className="d-flex w-100 justify-content-between align-items-start">
                      <strong className="small text-dark">{notif.title}</strong>
                      <small className="text-muted" style={{ fontSize: '0.7rem' }}>
                        {new Date(notif.created_at).toLocaleDateString()}
                      </small>
                    </div>
                    <p className="mb-0 small text-secondary mt-1">{notif.message}</p>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
